module top_module (
	input clk,
	input j,
	input k,
	output reg q);initial
		q = 0;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt) begin
		case ({j,k})
			2'b00: q <= q;
			2'b01: q <= 0;
			2'b10: q <= 1;
			2'b11: q <= ~q;
		endcase
	end

endmodule
